queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?capacity WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasDormitories ?child ; p:hasHostels ?parent . } GROUP BY ?child }
  ?child p:capacity ?capacity .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Hostels } }
  FILTER(?nf = ?total)
}

